import { test, expect } from '@playwright/test';

test('validate header navigation targets', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002/');

  // Check Home page header links
  const homeVideos = await page.getByRole('link', { name: 'videos', exact: true });
  await expect(homeVideos).toHaveAttribute('href', '/videos'); // This will fail as it is '/vidoes'

  const homeContact = await page.getByRole('link', { name: 'contact', exact: true });
  await expect(homeContact).toHaveAttribute('href', '/contact');

  // Navigate to 404 page to check header there
  await page.goto('http://localhost:3002/vidoes');
  const errorPageContact = await page.getByRole('link', { name: 'contact', exact: true });
  await expect(errorPageContact).toHaveAttribute('href', '/contact'); // This will fail as it is '/contcat'
});
